import{_ as e,c as t,o as s,ae as n}from"./chunks/framework.Cqi9LMMK.js";const c=JSON.parse('{"title":"Display modes","description":"","frontmatter":{"title":"Display modes"},"headers":[],"relativePath":"options/display_mode.md","filePath":"options/display_mode.md"}'),r={name:"options/display_mode.md"};function a(l,o,i,g,d,p){return s(),t("div",null,[...o[0]||(o[0]=[n('<h1 id="display-modes" tabindex="-1">Display modes <a class="header-anchor" href="#display-modes" aria-label="Permalink to &quot;Display modes&quot;">​</a></h1><p><strong>Options → General → Display Mode</strong> chooses <strong>where</strong> the Vue Inspector UI lives relative to the page: <strong>Overlay</strong> on the page or <strong>DevTools tab</strong> inside the browser’s developer tools.</p><blockquote><p><strong>DevTools mode requires the installed extension</strong> (Chrome / Edge). <strong>Standalone</strong> disables that toggle: the inspector only runs as an overlay; there is no DevTools panel.</p></blockquote><p>After changing mode the extension suggests <strong>reloading the page</strong>.</p><hr><h2 id="overlay-—-dock-pill-and-size" tabindex="-1">Overlay — dock, pill, and size <a class="header-anchor" href="#overlay-—-dock-pill-and-size" aria-label="Permalink to &quot;Overlay — dock, pill, and size&quot;">​</a></h2><p><strong>Overlay</strong> embeds the panel above the site in its own “window” in the tab.</p><p>The <strong>pill</strong> (compact handle with drag affordance and chevron) is the main control:</p><ul><li><strong>Chevron</strong> expands/collapses inspector chrome.</li><li><strong>Drag handle</strong> moves the block: near window edges it <strong>snaps</strong> top/bottom/left/right; centered becomes a <strong>floating</strong> framed window.</li></ul><p><strong>Default</strong> first open: docked to the <strong>bottom</strong> — full-width strip with the site visible above (resize height). Classic bottom dock.</p><p><strong>Resizing:</strong></p><ul><li>Docked: grab the <strong>outer</strong> edge (for bottom dock, the <strong>top</strong> border) to change height (bottom/top dock) or width (left/right).</li><li>Floating: corners and edges resize freely.</li></ul><p>Position, dock side, and floating geometry <strong>persist</strong> between visits (within browser/extension limits).</p><p>Whether the pill shows on a site can also depend on <strong>Auto Run</strong> lists — see <a href="/docs/options/auto_run.html">Auto run</a>.</p><hr><h2 id="devtools-tab" tabindex="-1">DevTools tab <a class="header-anchor" href="#devtools-tab" aria-label="Permalink to &quot;DevTools tab&quot;">​</a></h2><blockquote><p><strong>Extension only.</strong> The inspector opens as a <strong>separate tab</strong> inside native <strong>DevTools</strong> (F12 / Inspect), not as a floating overlay.</p></blockquote><p>Useful if you keep tools next to Console/Network or prefer not to cover the page. Pill dragging applies to <strong>Overlay</strong> only; DevTools layout follows the browser panel.</p><p>After switching to <strong>DevTools tab</strong>, <strong>reload</strong> and open DevTools — you should see <strong>Vue Inspector</strong> among panel tabs.</p><p><strong>Reload (F5):</strong> the inspector tab reconnects to <strong>this</strong> tab’s page context. No extra enable step.</p><p><strong>Versus Overlay:</strong> while overlay is <strong>collapsed</strong>, some page-side flows may not get a full channel to the expanded panel — <strong>Breakpoint</strong> / <strong>Mock</strong> may need you to <strong>expand</strong> first. In <strong>DevTools</strong> mode the inspector is already an <strong>active DevTools surface</strong>, so <strong>Network</strong> interception works <strong>immediately</strong> after reload.</p><p><strong>Network after F5:</strong> the request list <strong>clears and refills</strong> as the page reloads, but <strong>Network</strong> features (intercept, breakpoints, mocks) are <strong>ready from the start</strong> — no extra click to “wake” networking.</p><hr><h2 id="see-also" tabindex="-1">See also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See also&quot;">​</a></h2><ul><li><a href="/docs/options/auto_run.html">Auto run</a> — when the overlay pill auto-shows</li><li><a href="/docs/options/customize.html">Customize</a> — theme and panel background</li><li><a href="/docs/guide/extension.html">Browser extension</a></li></ul>',25)])])}const u=e(r,[["render",a]]);export{c as __pageData,u as default};
